/// <summary>
/// This class is an extension of SalesTable form, SalesLine datasource and Itemid field.
/// </summary>
[ExtensionOf(formDataFieldStr(SalesTable, SalesLine, ItemId))]
internal final class ETGSalesTable_SalesLine_ItemId_Extension
{
}

Method.Source:
/// <summary>
/// When Itemid field is modified, then deposit amount and deposit rate fields as non-editable based on flag.
/// </summary>
public void modified()
{
    boolean isEditable, isMandatory;
    next modified();

    if(SalesParameters::find().ETGEnableCylinderTracking)
    {
        FormDataObject    formDataObject    = any2Object(this) as FormDataObject;
        FormDataSource    formDataSource    = formDataObject.datasource();
        SalesLine         salesLine         = formDataSource.cursor();
        SalesTable        salesTable        = SalesTable::find(salesLine.SalesId);
        InventTableModule inventTableModule = InventTableModule::find(salesLine.ItemId, ModuleInventPurchSales::Sales);

        if(salesLine.ETGConnectionType == ETGConnectionType::NewConnectionorCylinder)
        {
            if(salesTable.ETGBusinessSegment == ETGBusinessSegment::Domestic)
            {
                isEditable  = true;
                isMandatory = true;
            }
            if(salesTable.ETGBusinessSegment == ETGBusinessSegment::Commercial
                || salesTable.ETGBusinessSegment == ETGBusinessSegment::Industrial
                || salesTable.ETGBusinessSegment == ETGBusinessSegment::Distributor)
            {
                isEditable  = true;
            }
        }

        if(salesLine.ETGConnectionType == ETGConnectionType::Surrenderofcylinders)
        {
            if(salesTable.ETGBusinessSegment == ETGBusinessSegment::Domestic)
            {
                isEditable  = true;
                isMandatory = true;
            }
            if(salesTable.ETGBusinessSegment == ETGBusinessSegment::Commercial
                || salesTable.ETGBusinessSegment == ETGBusinessSegment::Industrial
                || salesTable.ETGBusinessSegment == ETGBusinessSegment::Distributor)
            {
                isEditable  = true;
            }
        }

        formDataSource.object(fieldNum(SalesLine, ETGDepositRate)).allowEdit(inventTableModule.ETGDepositNeeded == NoYes::Yes && isEditable);
        formDataSource.object(fieldNum(SalesLine, ETGDepositAmount)).allowEdit(inventTableModule.ETGDepositNeeded == NoYes::Yes && isEditable);
        formDataSource.object(fieldNum(SalesLine, ETGDepositAmount)).mandatory(inventTableModule.ETGDepositNeeded == NoYes::Yes && isMandatory);
        formDataSource.object(fieldNum(SalesLine, SalesPrice)).allowEdit(inventTableModule.ETGDepositNeeded == NoYes::No);
        formDataSource.object(fieldNum(SalesLine, LineAmount)).allowEdit(inventTableModule.ETGDepositNeeded == NoYes::No);      
        formDataSource.object(fieldNum(SalesLine, ETGFilledOrEmpty)).allowEdit(inventTableModule.ETGFilledEmptyNeeded == NoYes::Yes);            
    }
}
